<?php

// Add batch transaction support to ProcessIncomingMessage.php
$file = 'app/Jobs/ProcessIncomingMessage.php';
$content = file_get_contents($file);

// Find the position after extractAmountFromText function (after line 4808)
$searchMarker = "    /**\n     * Extract amount from text line\n     * Supports: 17.000, 17000, 17rb, 17ribu, 17k\n     */\n    protected function extractAmountFromText(string \$text): ?int\n    {\n        \$textLower = strtolower(\$text);\n        \n        // Pattern 1: Number with suffix (60rb, 5jt, 25k)\n        // Use word boundary \\b to ensure suffix is not part of another word\n        if (preg_match('/\\b(\\d+(?:[.,]\\d+)?)\\s*(rb|ribu|k|jt|juta)\\b/i', \$textLower, \$matches)) {\n            \$num = floatval(str_replace(',', '.', \$matches[1]));\n            \$suffix = strtolower(\$matches[2]);\n            \n            \$multipliers = [\n                'rb' => 1000, 'ribu' => 1000, 'k' => 1000,\n                'jt' => 1000000, 'juta' => 1000000\n            ];\n            \n            return (int)(\$num * (\$multipliers[\$suffix] ?? 1));\n        }\n        \n        // Pattern 2: Plain number with dots (50.000)\n        if (preg_match('/(\\d{1,3}(?:\\.\\d{3})+)/', \$text, \$matches)) {\n            return (int)str_replace('.', '', \$matches[1]);\n        }\n        \n        // Pattern 3: Plain number at end (50000, at least 3 digits)\n        if (preg_match('/(\\d{3,})\$/', trim(\$text), \$matches)) {\n            return (int)\$matches[1];\n        }\n        \n        // Pattern 4: Number anywhere (fallback)\n        if (preg_match('/(\\d{4,})/', \$text, \$matches)) {\n            return (int)\$matches[1];\n        }\n        \n        return null;\n    }";

$newFunctions = "    /**\n     * Extract amount from text line\n     * Supports: 17.000, 17000, 17rb, 17ribu, 17k\n     * NOW SUPPORTS BATCH: Detects multiple amounts and sums them\n     */\n    protected function extractAmountFromText(string \$text): ?int\n    {\n        // Check if this is a batch transaction (multiple amounts)\n        if (\$this->isBatchTransaction(\$text)) {\n            \$amounts = \$this->extractAllAmountsFromText(\$text);\n            if (!empty(\$amounts)) {\n                \$total = array_sum(\$amounts);\n                Log::info('Batch transaction detected', [\n                    'text' => \$text,\n                    'amounts' => \$amounts,\n                    'total' => \$total\n                ]);\n                return \$total;\n            }\n        }\n        \n        // Single transaction - use original logic\n        \$textLower = strtolower(\$text);\n        \n        // Pattern 1: Number with suffix (60rb, 5jt, 25k)\n        // Use word boundary \\b to ensure suffix is not part of another word\n        if (preg_match('/\\b(\\d+(?:[.,]\\d+)?)\\s*(rb|ribu|k|jt|juta)\\b/i', \$textLower, \$matches)) {\n            \$num = floatval(str_replace(',', '.', \$matches[1]));\n            \$suffix = strtolower(\$matches[2]);\n            \n            \$multipliers = [\n                'rb' => 1000, 'ribu' => 1000, 'k' => 1000,\n                'jt' => 1000000, 'juta' => 1000000\n            ];\n            \n            return (int)(\$num * (\$multipliers[\$suffix] ?? 1));\n        }\n        \n        // Pattern 2: Plain number with dots (50.000)\n        if (preg_match('/(\\d{1,3}(?:\\.\\d{3})+)/', \$text, \$matches)) {\n            return (int)str_replace('.', '', \$matches[1]);\n        }\n        \n        // Pattern 3: Plain number at end (50000, at least 3 digits)\n        if (preg_match('/(\\d{3,})\$/', trim(\$text), \$matches)) {\n            return (int)\$matches[1];\n        }\n        \n        // Pattern 4: Number anywhere (fallback)\n        if (preg_match('/(\\d{4,})/', \$text, \$matches)) {\n            return (int)\$matches[1];\n        }\n        \n        return null;\n    }\n    \n    /**\n     * Check if text contains multiple amounts (batch transaction)\n     */\n    protected function isBatchTransaction(string \$text): bool\n    {\n        // Indicators of batch transaction:\n        // 1. Multiple lines with dashes/bullets\n        // 2. Multiple amounts found\n        // 3. Contains list markers (-, *, •, numbers)\n        \n        \$hasListMarkers = preg_match('/^\\s*[-*•]\\s+/m', \$text) || preg_match('/^\\s*\\d+[.)]/m', \$text);\n        \$amounts = \$this->extractAllAmountsFromText(\$text);\n        \$hasMultipleAmounts = count(\$amounts) >= 2;\n        \n        return \$hasListMarkers && \$hasMultipleAmounts;\n    }\n    \n    /**\n     * Extract ALL amounts from text (for batch transactions)\n     * Returns array of amounts\n     */\n    protected function extractAllAmountsFromText(string \$text): array\n    {\n        \$amounts = [];\n        \$textLower = strtolower(\$text);\n        \n        // Pattern 1: Numbers with suffix (10k, 5rb, 2jt)\n        if (preg_match_all('/\\b(\\d+(?:[.,]\\d+)?)\\s*(rb|ribu|k|jt|juta)\\b/i', \$textLower, \$matches, PREG_SET_ORDER)) {\n            foreach (\$matches as \$match) {\n                \$num = floatval(str_replace(',', '.', \$match[1]));\n                \$suffix = strtolower(\$match[2]);\n                \n                \$multipliers = [\n                    'rb' => 1000, 'ribu' => 1000, 'k' => 1000,\n                    'jt' => 1000000, 'juta' => 1000000\n                ];\n                \n                \$amounts[] = (int)(\$num * (\$multipliers[\$suffix] ?? 1));\n            }\n        }\n        \n        // Pattern 2: Plain numbers with dots (10.000, 25.000)\n        if (preg_match_all('/(\\d{1,3}(?:\\.\\d{3})+)/', \$text, \$matches)) {\n            foreach (\$matches[1] as \$match) {\n                \$amounts[] = (int)str_replace('.', '', \$match);\n            }\n        }\n        \n        return \$amounts;\n    }";

$content = str_replace($searchMarker, $newFunctions, $content);
file_put_contents($file, $content);

echo "✅ Updated: ProcessIncomingMessage.php\n";
echo "\n📦 BATCH TRANSACTION SUPPORT ADDED!\n\n";
echo "New features:\n";
echo "  1. ✅ Detects multiple amounts in one message\n";
echo "  2. ✅ Automatically sums all amounts\n";
echo "  3. ✅ Works with list format (-, *, •, numbers)\n";
